DB_PATH = os.getenv("SECUREAI_DB_PATH", "/tmp/secureai.db")

def _dict_factory(cursor, row):
    return {col[0]: row[idx] for idx, col in enumerate(cursor.description)}

@contextmanager
def get_conn():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = _dict_factory
    conn.execute("PRAGMA foreign_keys = ON")
    try:
        yield conn
        conn.commit()
    finally:
        conn.close()

def now_iso():
    return datetime.utcnow().isoformat()

_INIT_SQL = """
CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT,username TEXT UNIQUE NOT NULL,email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,preferred_language TEXT DEFAULT 'ar',created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS scans (id INTEGER PRIMARY KEY AUTOINCREMENT,user_id INTEGER,target TEXT NOT NULL,scan_type TEXT NOT NULL,result_json TEXT NOT NULL,created_at TEXT NOT NULL,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS alerts (id INTEGER PRIMARY KEY AUTOINCREMENT,message TEXT NOT NULL,level TEXT NOT NULL,target TEXT,channel TEXT DEFAULT 'system',created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS monitors (id INTEGER PRIMARY KEY AUTOINCREMENT,user_id INTEGER,url TEXT UNIQUE NOT NULL,content_hash TEXT,last_check TEXT,interval_seconds INTEGER DEFAULT 300,checks INTEGER DEFAULT 0,changes INTEGER DEFAULT 0,created_at TEXT NOT NULL,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS monitor_history (id INTEGER PRIMARY KEY AUTOINCREMENT,monitor_id INTEGER NOT NULL,event_type TEXT NOT NULL,details TEXT,created_at TEXT NOT NULL,FOREIGN KEY(monitor_id) REFERENCES monitors(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS notification_settings (id INTEGER PRIMARY KEY CHECK (id = 1),telegram_bot_token TEXT,telegram_chat_id TEXT,discord_webhook TEXT,slack_webhook TEXT,smtp_host TEXT,smtp_port INTEGER DEFAULT 587,smtp_user TEXT,smtp_password TEXT,smtp_sender TEXT,smtp_use_tls INTEGER DEFAULT 1,updated_at TEXT NOT NULL);
"""

def init_db():
    with get_conn() as conn:
        conn.executescript(_INIT_SQL)
        if not conn.execute("SELECT id FROM notification_settings WHERE id=1").fetchone():
            conn.execute("INSERT INTO notification_settings (id,telegram_bot_token,telegram_chat_id,discord_webhook,slack_webhook,smtp_host,smtp_port,smtp_user,smtp_password,smtp_sender,smtp_use_tls,updated_at) VALUES (1,?,?,?,?,?,587,?,?,?,1,?)",("","","","","","","","",now_iso()))

