        conn.execute("INSERT INTO users (username,email,password_hash,preferred_language,created_at) VALUES (?,?,?,?,?)",(username,email.lower(),pw_hash,lang,now_iso()))
        return conn.execute("SELECT id,username,email,preferred_language,created_at FROM users WHERE email=?",(email.lower(),)).fetchone()

