def save_scan(user_id,target,scan_type,result):
    with get_conn() as conn:
        conn.execute("INSERT INTO scans (user_id,target,scan_type,result_json,created_at) VALUES (?,?,?,?,?)",(user_id,target,scan_type,json.dumps(result,ensure_ascii=False),now_iso()))

def get_recent_scans(limit=50,user_id=None):
    q="SELECT * FROM scans"+(" WHERE user_id=?" if user_id else "")+" ORDER BY id DESC LIMIT ?"
    params=([user_id,limit] if user_id else [limit])
    with get_conn() as conn:
        rows=conn.execute(q,tuple(params)).fetchall()
    for row in rows:
        try: row["result"]=json.loads(row.pop("result_json"))
        except Exception: row["result"]={}
    return rows

def get_stats_summary(user_id=None):
    with get_conn() as conn:
        q="SELECT COUNT(*) AS c FROM scans"+(" WHERE user_id=?" if user_id else "")
        total_scans=conn.execute(q,(user_id,) if user_id else ()).fetchone()["c"]
        mq="SELECT COUNT(*) AS c FROM monitors"+(" WHERE user_id=?" if user_id else "")
        monitored=conn.execute(mq,(user_id,) if user_id else ()).fetchone()["c"]
        alerts_count=conn.execute("SELECT COUNT(*) AS c FROM alerts").fetchone()["c"]
    recent=get_recent_scans(50,user_id)
    return {"total_scans":total_scans,"total_threats":sum(len(i.get("result",{}).get("threats",[])) for i in recent),"ports_scanned":sum(i.get("result",{}).get("open_count",0) for i in recent),"leaks_found":sum(i.get("result",{}).get("leaks_found",0) for i in recent),"monitored_sites":monitored,"alerts_count":alerts_count,"scan_history":[{"type":i.get("scan_type"),"target":i.get("target"),"timestamp":i.get("created_at")} for i in recent[::-1]]}

