        conn.execute("UPDATE notification_settings SET telegram_bot_token=?,telegram_chat_id=?,discord_webhook=?,slack_webhook=?,smtp_host=?,smtp_port=?,smtp_user=?,smtp_password=?,smtp_sender=?,smtp_use_tls=?,updated_at=? WHERE id=1",(merged.get("telegram_bot_token",""),merged.get("telegram_chat_id",""),merged.get("discord_webhook",""),merged.get("slack_webhook",""),merged.get("smtp_host",""),int(merged.get("smtp_port",587) or 587),merged.get("smtp_user",""),merged.get("smtp_password",""),merged.get("smtp_sender",""),1 if merged.get("smtp_use_tls",True) else 0,merged["updated_at"]))
