def upsert_monitor(user_id,url,content_hash,interval_seconds=300):
    with get_conn() as conn:
        row=conn.execute("SELECT * FROM monitors WHERE url=?",(url,)).fetchone()
        if row: conn.execute("UPDATE monitors SET user_id=COALESCE(?,user_id),content_hash=?,last_check=?,interval_seconds=?,checks=COALESCE(checks,0)+1 WHERE url=?",(user_id,content_hash,now_iso(),interval_seconds,url))
        else: conn.execute("INSERT INTO monitors (user_id,url,content_hash,last_check,interval_seconds,checks,changes,created_at) VALUES (?,?,?,?,?,1,0,?)",(user_id,url,content_hash,now_iso(),interval_seconds,now_iso()))
        return conn.execute("SELECT * FROM monitors WHERE url=?",(url,)).fetchone()

def list_monitors(user_id=None):
    with get_conn() as conn:
        if user_id is None: return conn.execute("SELECT * FROM monitors ORDER BY id DESC").fetchall()
        return conn.execute("SELECT * FROM monitors WHERE user_id=? ORDER BY id DESC",(user_id,)).fetchall()

def update_monitor_state(url,content_hash,changed=False,details=""):
    with get_conn() as conn:
        monitor=conn.execute("SELECT * FROM monitors WHERE url=?",(url,)).fetchone()
        if not monitor: return None
        conn.execute("UPDATE monitors SET content_hash=?,last_check=?,checks=checks+1,changes=changes+? WHERE url=?",(content_hash,now_iso(),1 if changed else 0,url))
        updated=conn.execute("SELECT * FROM monitors WHERE url=?",(url,)).fetchone()
        if changed: conn.execute("INSERT INTO monitor_history (monitor_id,event_type,details,created_at) VALUES (?,?,?,?)",(updated["id"],"change",details,now_iso()))
        return updated

def delete_monitor(url):
    with get_conn() as conn:
        return conn.execute("DELETE FROM monitors WHERE url=?",(url,)).rowcount>0

JWT_SECRET=os.getenv("SECUREAI_JWT_SECRET","secureai-change-me")
JWT_EXPIRE=int(os.getenv("SECUREAI_JWT_EXPIRE_SECONDS","43200"))

def _enc(d:bytes)->str: return base64.urlsafe_b64encode(d).rstrip(b"=").decode()
def _dec(d:str)->bytes: return base64.urlsafe_b64decode(d+"="*(-len(d)%4))

def hash_password(password:str)->str:
    salt=secrets.token_bytes(16)
    dk=hashlib.pbkdf2_hmac("sha256",password.encode(),salt,120000)
    return f"pbkdf2_sha256${_enc(salt)}${_enc(dk)}"

def verify_password(password:str,stored:str)->bool:
    try:
        _,s,h=stored.split("$",2)
        return hmac.compare_digest(hashlib.pbkdf2_hmac("sha256",password.encode(),_dec(s),120000),_dec(h))
    except Exception: return False

def create_jwt(user:dict)->str:
    hdr=_enc(json.dumps({"alg":"HS256","typ":"JWT"},separators=(",",":")).encode())
    now=int(time.time())
    pld=_enc(json.dumps({"sub":str(user["id"]),"email":user["email"],"username":user["username"],"iat":now,"exp":now+JWT_EXPIRE},separators=(",",":")).encode())
    sig=hmac.new(JWT_SECRET.encode(),f"{hdr}.{pld}".encode(),hashlib.sha256).digest()
    return f"{hdr}.{pld}.{_enc(sig)}"

def decode_jwt(token:str)->dict:
    try:
        h,p,s=token.split(".")
        expected=hmac.new(JWT_SECRET.encode(),f"{h}.{p}".encode(),hashlib.sha256).digest()
        if not hmac.compare_digest(expected,_dec(s)): raise HTTPException(401,"رمز الوصول غير صالح")
        payload=json.loads(_dec(p))
        if int(payload.get("exp",0))<int(time.time()): raise HTTPException(401,"انتهت صلاحية الجلسة")
        return payload
    except HTTPException: raise
    except Exception: raise HTTPException(401,"تعذر التحقق")

def authenticate_user(email:str,password:str):
    user=get_user_by_email(email)
    if not user or not verify_password(password,user.get("password_hash","")): return None
    return user

def get_current_user(authorization:Optional[str]=Header(default=None))->dict:
    if not authorization or not authorization.startswith("Bearer "): raise HTTPException(401,"يلزم تسجيل الدخول")
    payload=decode_jwt(authorization.split(" ",1)[1].strip())
    user=get_user_by_id(int(payload["sub"]))
    if not user: raise HTTPException(401,"المستخدم غير موجود")
    return user

async def send_telegram(msg:str,s=None)->dict:
    s=s or get_notification_settings()
    tok=(s.get("telegram_bot_token") or "").strip()
    cid=(s.get("telegram_chat_id") or "").strip()
    if not tok or not cid: return {"success":False,"channel":"telegram"}
    async with httpx.AsyncClient(timeout=15.0) as client:
        r=await client.post(f"https://api.telegram.org/bot{tok}/sendMessage",json={"chat_id":cid,"text":msg})
    return {"success":r.status_code<400,"channel":"telegram"}

async def send_webhook(msg:str,wurl:str,wtype:str)->dict:
    if not wurl: return {"success":False,"channel":wtype}
    payload={"content":msg} if wtype=="discord" else {"text":msg}
    async with httpx.AsyncClient(timeout=15.0) as client:
        r=await client.post(wurl,json=payload)
    return {"success":r.status_code<400,"channel":wtype}

async def send_email_message(to_email,subject,body,html_body=None,settings=None):
    s=settings or get_notification_settings()
    host=(s.get("smtp_host") or "").strip()
    user=(s.get("smtp_user") or "").strip()
    pw=s.get("smtp_password") or ""
    sender=(s.get("smtp_sender") or user).strip()
    port=int(s.get("smtp_port") or 587)
    tls=bool(s.get("smtp_use_tls",1))
    if not host or not sender: return {"success":False,"error":"SMTP not configured"}
    msg=MIMEMultipart("alternative")
    msg["Subject"]=subject; msg["From"]=sender; msg["To"]=to_email
    msg.attach(MIMEText(body,"plain","utf-8"))
    if html_body: msg.attach(MIMEText(html_body,"html","utf-8"))
    def _s():
        srv=smtplib.SMTP(host,port,timeout=20)
        try:
            srv.ehlo()
            if tls: srv.starttls(); srv.ehlo()
            if user: srv.login(user,pw)
            srv.sendmail(sender,[to_email],msg.as_string())
        finally:
            try: srv.quit()
            except: pass
    try:
        await asyncio.to_thread(_s)
        return {"success":True,"to":to_email}
    except Exception as exc: return {"success":False,"error":str(exc)}

async def broadcast_alert(message:str,settings=None)->dict:
    s=settings or get_notification_settings()
    results=[]
    if s.get("telegram_bot_token") and s.get("telegram_chat_id"): results.append(await send_telegram(message,s))
    if s.get("discord_webhook"): results.append(await send_webhook(message,s["discord_webhook"],"discord"))
    if s.get("slack_webhook"): results.append(await send_webhook(message,s["slack_webhook"],"slack"))
    return {"success":any(r.get("success") for r in results) if results else False,"results":results}

MONITOR_POLL_SECONDS=60

def _hc(c:str)->str: return hashlib.sha256(c.encode("utf-8",errors="ignore")).hexdigest()

async def _push(alert:dict):
    try: await broadcast_alert(f"[{alert.get('level','info').upper()}] {alert.get('message','')}")
    except Exception: pass

def send_alert(message:str,level:str="info",target=None):
    alert=save_alert_db(message,level,target)
    logger.info("alert",level=level,msg=message)
    try: asyncio.get_running_loop().create_task(_push(alert))
    except Exception: pass
    return alert

async def add_monitor(url:str,interval:int=300,user_id=None):
    if not url.startswith(("http://","https://")): url="https://"+url
    try:
        async with httpx.AsyncClient(timeout=12.0,follow_redirects=True) as client:
            r=await client.get(url)
        upsert_monitor(user_id,url,_hc(r.text),interval_seconds=interval)
        send_alert(f"مراقبة بدأت: {url}","info",url)
        return {"success":True,"url":url,"interval":interval}
    except Exception as e: return {"success":False,"error":str(e)}

def remove_monitor(url:str):
    if delete_monitor(url):
        send_alert(f"مراقبة توقفت: {url}","info",url)
        return {"success":True}
    return {"success":False,"error":"الموقع غير مراقب"}

async def check_changes():
    for m in list_monitors():
        u=m["url"]
        try:
            async with httpx.AsyncClient(timeout=12.0,follow_redirects=True) as client:
                r=await client.get(u)
            nh=_hc(r.text)
            changed=nh!=(m.get("content_hash") or "")
            update_monitor_state(u,nh,changed=changed,details="changed" if changed else "ok")
            if changed: send_alert(f"تغيير في {u}","warning",u)
        except Exception as e: send_alert(f"تعذر فحص {u}: {e}","warning",u)

async def monitor_loop():
    while True:
        try: await check_changes()
        except Exception as e: logger.info("monitor_err",error=str(e))
        await asyncio.sleep(MONITOR_POLL_SECONDS)

_SHDR={"content-security-policy":"CSP","x-frame-options":"X-Frame-Options","x-content-type-options":"X-Content-Type-Options","strict-transport-security":"HSTS","referrer-policy":"Referrer-Policy","permissions-policy":"Permissions-Policy","x-xss-protection":"X-XSS-Protection"}
_MIXED_RE=re.compile(r"http://\S+")
_APIKEY_RE=re.compile(r"(?:api.?key|apikey|secret|token|password)\s*[:=]\s*.{1,60}",re.I)

def detect_threats(headers:dict,html_content:str,url:str="")->list:
    issues=[]
    hl={k.lower():v for k,v in headers.items()}
    hc=html_content.lower() if html_content else ""
    for header,desc in _SHDR.items():
        if header not in hl: issues.append(f"\u26a0\ufe0f عنوان مفقود: {header} ({desc})")
    if "<script" in hc:
        chunks=hc.split("<script")[:5]
        if any("src=" not in c[:200] for c in chunks[1:]): issues.append("\U0001f534 Inline Scripts - خطر XSS")
    if url.startswith("https://") and _MIXED_RE.search(hc): issues.append("\U0001f534 Mixed Content")
    if _APIKEY_RE.search(hc): issues.append("\U0001f6a8 احتمال تسريب مفاتيح API")
    if "eval(" in hc or "document.write" in hc: issues.append("\u26a0\ufe0f دوال خطرة")
    if "set-cookie" in hl:
        cookie=hl["set-cookie"].lower()
        if "httponly" not in cookie: issues.append("\u26a0\ufe0f الكوكيز بدون HttpOnly")
        if "secure" not in cookie: issues.append("\u26a0\ufe0f الكوكيز بدون Secure")
        if "samesite" not in cookie: issues.append("\u26a0\ufe0f الكوكيز بدون SameSite")
    if any(t in hc for t in ["index of /","directory listing for","phpinfo()"]): issues.append("\U0001f534 Directory Listing")
    if re.search(r"sql syntax|mysql_fetch|postgresql query failed",hc): issues.append("\U0001f6a8 رسائل أخطاء قاعدة بيانات")
    if "server" in hl and any(v in hl["server"].lower() for v in ["apache/2.2","nginx/1.0","php/5"]): issues.append(f"\U0001f534 إصدار خادم قديم: {hl['server']}")
    if "x-powered-by" in hl: issues.append(f"\u26a0\ufe0f X-Powered-By: {hl['x-powered-by']}")
    return issues

def calculate_risk_score(threats:list)->dict:
    if not threats: return {"level":"آمن","score":0,"color":"#00ff88"}
    critical=sum(1 for t in threats if "🚨" in t or "🔴" in t)
    warnings=sum(1 for t in threats if "⚠️" in t)
    score=min(100,critical*25+warnings*10)
    if score>=70: return {"level":"خطر","score":score,"color":"#ff4444"}
    if score>=40: return {"level":"تحذير","score":score,"color":"#ffaa00"}
    return {"level":"منخفض","score":score,"color":"#ffdd00"}

