def _ai(lang): return _AI.get(lang or "ar",_AI["ar"])

def ai_analyze(url,threats,risk=None,lang="ar")->dict:
    b=_ai(lang)
    ts=datetime.utcnow().strftime("%Y-%m-%d %H:%M UTC")
    if not threats: return {"timestamp":ts,"summary":f"✅ {url}","risk_level":"آمن","risk_score":0,"verdict":b["sv"],"details":[],"recommendations":b["sr"],"ai_insight":b["si"]}
    cc=sum(1 for t in threats if "🚨" in t or "🔴" in t)
    ins=b["ic"] if cc>=3 else (b["im"] if cc>=1 else b["iw"])
    return {"timestamp":ts,"summary":f"🔍 {url}","risk_level":risk.get("level") if risk else None,"risk_score":risk.get("score",len(threats)*10) if risk else len(threats)*10,"verdict":b["v"].format(n=len(threats)),"details":threats,"recommendations":["راجع إعدادات الأمان"],"ai_insight":ins}

def generate_username_insight(username,results,lang="ar")->str:
    b=_ai(lang)
    found=[r for r in results if r.get("found")]
    if not found: return b["un"].format(u=username)
    platforms=", ".join(r["platform"] for r in found[:5])
    return b["ui"].format(c=len(found),t=len(results),p=platforms)+(b["uc"] if len(found)>7 else b["ul"])

async def scan_site(url:str,lang="ar")->dict:
    if not url.startswith(("http://","https://")): url="https://"+url
    try:
        async with httpx.AsyncClient(timeout=15.0,follow_redirects=True) as client:
            r=await client.get(url)
        threats=detect_threats(dict(r.headers),r.text,url=url)
        risk=calculate_risk_score(threats)
        ai_report=ai_analyze(url,threats,risk,lang=lang)
        return {"url":url,"status":r.status_code,"final_url":str(r.url),"threats":threats,"risk":risk,"ai_report":ai_report,"headers_count":len(r.headers),"page_size":len(r.text),"language":lang}
    except httpx.TimeoutException: return {"url":url,"error":"Timeout","language":lang}
    except Exception as e: return {"url":url,"error":str(e),"language":lang}

