ADMIN_KEY = os.getenv("SECUREAI_ADMIN_KEY", "")


def get_admin(x_admin_key: Optional[str] = Header(default=None)):
    """Admin authentication via X-Admin-Key header"""
    if not ADMIN_KEY:
        raise HTTPException(503, "لوحة Admin غير مفعّلة — أضف SECUREAI_ADMIN_KEY في الإعدادات")
    if x_admin_key != ADMIN_KEY:
        raise HTTPException(401, "مفتاح Admin غير صحيح")
    return True


@app.get("/admin/stats")
async def admin_stats(_=Depends(get_admin)):
    """إحصائيات النظام الكاملة"""
    with get_conn() as conn:
        users_count = conn.execute("SELECT COUNT(*) AS c FROM users").fetchone()["c"]
        scans_count = conn.execute("SELECT COUNT(*) AS c FROM scans").fetchone()["c"]
        alerts_count = conn.execute("SELECT COUNT(*) AS c FROM alerts").fetchone()["c"]
        monitors_count = conn.execute("SELECT COUNT(*) AS c FROM monitors").fetchone()["c"]
        recent_scans = conn.execute("SELECT scan_type, COUNT(*) AS c FROM scans GROUP BY scan_type ORDER BY c DESC").fetchall()
        top_targets = conn.execute("SELECT target, COUNT(*) AS c FROM scans GROUP BY target ORDER BY c DESC LIMIT 10").fetchall()
    return {
        "users": users_count,
        "total_scans": scans_count,
        "total_alerts": alerts_count,
        "active_monitors": monitors_count,
        "scans_by_type": recent_scans,
        "top_targets": top_targets,
    }


@app.get("/admin/users")
async def admin_list_users(_=Depends(get_admin)):
    """قائمة جميع المستخدمين"""
    with get_conn() as conn:
        users = conn.execute("SELECT id, username, email, preferred_language, created_at FROM users ORDER BY id DESC").fetchall()
        for u in users:
            cnt = conn.execute("SELECT COUNT(*) AS c FROM scans WHERE user_id=?", (u["id"],)).fetchone()["c"]
            u["scan_count"] = cnt
    return {"users": users, "total": len(users)}


@app.delete("/admin/users/{user_id}")
async def admin_delete_user(user_id: int, _=Depends(get_admin)):
    """حذف مستخدم"""
    with get_conn() as conn:
        user = conn.execute("SELECT * FROM users WHERE id=?", (user_id,)).fetchone()
        if not user:
            raise HTTPException(404, "المستخدم غير موجود")
        conn.execute("DELETE FROM users WHERE id=?", (user_id,))
    return {"success": True, "deleted_user": user_id}


@app.get("/admin/scans")
async def admin_list_scans(limit: int = Query(50, ge=1, le=500), _=Depends(get_admin)):
    """جميع الفحوصات لجميع المستخدمين"""
    scans = get_recent_scans(limit=limit, user_id=None)
    return {"scans": scans, "total": len(scans)}


@app.delete("/admin/scans/clear")
async def admin_clear_scans(_=Depends(get_admin)):
    """مسح جميع سجلات الفحوصات"""
    with get_conn() as conn:
        count = conn.execute("SELECT COUNT(*) AS c FROM scans").fetchone()["c"]
        conn.execute("DELETE FROM scans")
    return {"success": True, "deleted_count": count}


